<div class="bubbles-container" id="bubbles-container"></div>
<script>
(function() {
  const container = document.getElementById('bubbles-container');

  function makeBubble() {
    const b = document.createElement('div');
    b.className = 'bubble';
    const size = Math.random() * 60 + 20;
    b.style.cssText = `
      width: ${size}px;
      height: ${size}px;
      left: ${Math.random() * 100}vw;
      animation-duration: ${Math.random() * 14 + 10}s;
      animation-delay: ${Math.random() * 12}s;
      --drift: ${(Math.random() - 0.5) * 120}px;
      --end-scale: ${0.7 + Math.random() * 0.6};
    `;

    b.addEventListener('click', function(e) {
      e.stopPropagation();
      if (b.dataset.popping) return;
      b.dataset.popping = 'true';

      const rect = b.getBoundingClientRect();
      b.style.animation = 'none';
      b.style.position = 'fixed';
      b.style.left = rect.left + 'px';
      b.style.top = rect.top + 'px';
      b.style.opacity = '1';
      b.style.transform = 'none';

      b.style.transition = 'transform 0.15s ease-out, opacity 0.15s ease-out';
      requestAnimationFrame(function() {
        requestAnimationFrame(function() {
          b.style.transform = 'scale(1.6)';
          b.style.opacity = '0';
        });
      });

      const sfx = document.getElementById('sfx-close');
      if (sfx) { sfx.currentTime = 0; sfx.play(); }

      setTimeout(function() {
        b.remove();
        makeBubble();
      }, 200);
    });

    container.appendChild(b);
    return b;
  }

  for (let i = 0; i < 40; i++) {
    makeBubble();
  }
})();
</script>
